    def parse(cls, phone_number) -> Any:
        for code, region in cls.cc01Map.items():
            if phone_number.startswith(code):
                if region != "ZZ":
                    return region
                # Secondary match
                secondary_map = cls.cc02Map.get(code, {})
                regex_value = phone_number[len(code):]
